// src/elementi/RezervacijeRecepcionar.js
import { useEffect, useState } from "react";
import NavBarRecepcionar from "./NavBarRecepcionar"; // default import
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";

export function RezervacijeRecepcionar() {
  const [rezervacije, setRezervacije] = useState([]);
  const [filterStatus, setFilterStatus] = useState("ALL");

  // Učitavanje svih rezervacija
  useEffect(() => {
    fetch("http://localhost:8080/reservations/all")
      .then((res) => res.json())
      .then((data) => {
        if (data?.data?.values) setRezervacije(data.data.values);
      })
      .catch((err) => console.error("Greška pri učitavanju rezervacija:", err));
  }, []);

  // Filtriranje rezervacija po statusu
  const filtriraneRezervacije =
    filterStatus === "ALL"
      ? rezervacije
      : rezervacije.filter((r) => r.statusRezervacije === filterStatus);

  // Promena statusa rezervacije
  const handleStatusChange = async (rez, noviStatus) => {
    try {
      await fetch("http://localhost:8080/reservations/update", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...rez, statusRezervacije: noviStatus }),
      });

      // Ažuriranje stanja lokalno
      setRezervacije((prev) =>
        prev.map((r) =>
          r.idRezervacija === rez.idRezervacija
            ? { ...r, statusRezervacije: noviStatus }
            : r
        )
      );
    } catch (err) {
      console.error("Greška pri promeni statusa:", err);
      alert("Došlo je do greške prilikom promene statusa rezervacije.");
    }
  };

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", justifyContent: "space-between" }}>
      <NavBarRecepcionar />

      <div
        style={{
          backgroundImage: `url(${pattern})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: "100vh",
          padding: "40px",
        }}
      >
        <h2
          style={{
            textAlign: "center",
            color: "white",
            backgroundColor: "rgba(226, 108, 255, 0.7)",
            padding: "15px 30px",
            borderRadius: "10px",
            display: "inline-block",
            marginBottom: "30px",
          }}
        >
          Sve rezervacije
        </h2>

        <div style={{ marginBottom: "20px", textAlign: "center" }}>
          <label style={{ marginRight: "10px", color: "white", fontWeight: "bold" }}>Filtriraj po statusu:</label>
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            style={{ padding: "5px 10px", borderRadius: "5px" }}
          >
            <option value="ALL">Sve</option>
            <option value="PENDING">Na čekanju</option>
            <option value="CONFIRMED">Potvrđene</option>
            <option value="CANCELLED">Otkazane</option>
          </select>
        </div>

        <div style={{ display: "flex", flexWrap: "wrap", gap: "20px", justifyContent: "center" }}>
          {filtriraneRezervacije.map((r) => (
            <div
              key={r.idRezervacija}
              style={{
                backgroundColor: "rgba(255,255,255,0.9)",
                width: "300px",
                borderRadius: "10px",
                padding: "15px",
                boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
              }}
            >
              <h3>{r.soba?.naziv || "Nepoznata soba"}</h3>
              <p>
                <strong>Status:</strong> {r.statusRezervacije}
              </p>
              <p>
                <strong>Datum prijave:</strong> {r.datumPrijave}
              </p>
              <p>
                <strong>Datum odjave:</strong> {r.datumOdjave}
              </p>

              <div style={{ display: "flex", justifyContent: "flex-end", gap: "10px", marginTop: "10px" }}>
                <button
                  onClick={() => handleStatusChange(r, "CONFIRMED")}
                  style={{
                    backgroundColor: "#61e3dd",
                    border: "none",
                    borderRadius: "5px",
                    padding: "5px 10px",
                    cursor: "pointer",
                  }}
                >
                  ✅ Potvrdi
                </button>
                <button
                  onClick={() => handleStatusChange(r, "CANCELLED")}
                  style={{
                    backgroundColor: "#e36161",
                    border: "none",
                    borderRadius: "5px",
                    padding: "5px 10px",
                    cursor: "pointer",
                  }}
                >
                  ❌ Odbij
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      <Footer />
    </div>
  );
}
